@page "/catalog"
@attribute [StreamRendering]
@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="Search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="DepartmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Any())
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    var dept = CatalogService.GetDepartment(course.DepartmentId);
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}
else
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@attribute [StreamRendering]
@inject ICatalogService CatalogService

<PageTitle>Enroll</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Input.StudentName</strong>. Your enrollment request for <strong>@(CatalogService.GetCourse(Input.CourseId)?.Title)</strong> has been received.</p>
        <hr />
        <p class="mb-0"><a href="/catalog" class="alert-link">Browse more courses</a> or <a href="/enroll" class="alert-link">submit another request</a>.</p>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm Model="Input" FormName="enroll" OnValidSubmit="HandleSubmit" method="post">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger mb-3" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Student Name</label>
                    <InputText id="studentName" @bind-Value="Input.StudentName" class="form-control" />
                    <ValidationMessage For="() => Input.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" @bind-Value="Input.StudentId" class="form-control" />
                    <ValidationMessage For="() => Input.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" @bind-Value="Input.CourseId" class="form-select">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Input.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Input { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses(null, null);
        if (CourseId.HasValue && Input.CourseId == 0)
        {
            Input.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(Input);
        submitted = true;
    }
}

